        sdg1_un_target_1_2_label: `UN Target 1.2:`,
        sdg1_un_target_1_2_text: `By 2030, reduce at least by half the proportion of men, women and children of all ages living in poverty in all its dimensions according to national definitions.`,
        sdg1_un_target_1_4_label: `UN Target 1.4:`,
        sdg1_un_target_1_4_text: `By 2030, ensure that all men and women, in particular the poor and the vulnerable, have equal rights to economic resources, as well as access to basic services ... ownership and control over land and other forms of property, inheritance, natural resources, appropriate new technology and financial services, including microfinance.`,
        sdg1_un_target_1_5_label: `UN Target 1.5:`,
        sdg1_un_target_1_5_text: `By 2030, build the resilience of the poor and those in vulnerable situations and reduce their exposure and vulnerability to climate-related extreme events and other economic, social and environmental shocks and disasters.`,
