        sdg4_un_target_4_3_label: `UN Target 4.3:`,
        sdg4_un_target_4_3_text: `By 2030, ensure equal access for all women and men to affordable and quality technical, vocational and tertiary education, including university.`,
        sdg4_un_target_4_a1_label: `4.a.1:`,
        sdg4_un_target_4_a1_text: `Proportion of schools with access to: (a) electricity; (b) the Internet for pedagogical purposes; (c) computers for pedagogical purposes; (d) adapted infrastructure and materials for students with disabilities; (e) basic drinking water; (f) single-sex basic sanitation facilities; and (g) basic handwashing facilities (as per the WASH indicator definitions)`,
        sdg4_un_target_4_a_label: `4.A:`,
        sdg4_un_target_4_a_text: `Build and upgrade education facilities that are child, disability and gender sensitive and provide safe, nonviolent, inclusive and effective learning environments for all.`,
