        sdg6_un_target_6_3_label: `UN Target 6.3:`,
        sdg6_un_target_6_3_text: `By 2030, improve water quality by reducing pollution, eliminating dumping and minimizing release of hazardous chemicals and materials, halving the proportion of untreated wastewater and substantially increasing recycling and safe reuse globally. > BUILDING CONSTRUCTION WITHOUT WATER POLLUTION`,
        sdg6_un_target_6_4_label: `UN Target 6.4:`,
        sdg6_un_target_6_4_text: `By 2030, substantially increase water-use efficiency across all sectors and ensure sustainable withdrawals and supply of freshwater to address water scarcity and substantially reduce the number of people suffering from water scarcity. > REDUCE WATER CONSUMPTION IN CONSTRUCTION AND USE`,
        sdg6_un_target_6_6_label: `UN Target 6.6:`,
        sdg6_un_target_6_6_text: `By 2020, protect and restore water-related ecosystems, including mountains, forests, wetlands, rivers, aquifers and lakes.`,
