// Global availability
window.translations = translations;
window.currentLanguage = currentLanguage;

// Function to set language and update UI
function setLanguage(lang) {
    // Bulletproof mapping for Portuguese variants
    if (lang === 'pt') lang = 'pt-br';
    
    if (!translations[lang]) { 
        console.warn('Language ' + lang + ' not supported, falling back to English');
        lang = 'en';
    }
    
    currentLanguage = lang;
    window.currentLanguage = lang; // Ensure global sync for charting
    
    // Update button states in switcher
    document.querySelectorAll('.lang-btn').forEach(btn => {
        const btnLang = btn.getAttribute('data-lang');
        if (btnLang === lang || (lang === 'pt-br' && btnLang === 'pt')) {
            btn.classList.add('lang-btn-active');
        } else {
            btn.classList.remove('lang-btn-active');
        }
    });

    // Trigger UI update if function exists (provided by ui_assessment.js)
    if (typeof updateUIForLanguage === 'function') {
        updateUIForLanguage();
    }
    
    // Store preference using consistent key used by main_assessment.js
    localStorage.setItem('sdgAssessmentLang', lang);
}

// Load preference on start
document.addEventListener('DOMContentLoaded', () => {
    // ALWAYS check localStorage first, but default to English if empty
    const savedLang = localStorage.getItem('sdgAssessmentLang');
    if (savedLang && (translations[savedLang] || savedLang === 'pt')) {
        setLanguage(savedLang);
    } else {
        // Default is English, ignore browser settings
        setLanguage('en');
    }
});

if (typeof module !== 'undefined' && module.exports) module.exports = translations;